"""PostToolUse hook: detect encoding changes in source files.

Compares the file's encoding after Edit/Write against the HEAD version in git.
If the encoding changed (e.g. cp932 -> utf-8), outputs a warning to stdout
which Claude will see as feedback.
"""

import json
import os
import subprocess
import sys


SOURCE_EXTS = {".c", ".h", ".cpp", ".hpp"}


def detect_encoding(data: bytes) -> str | None:
    """Detect encoding by trying cp932 then utf-8."""
    for enc in ("cp932", "utf-8"):
        try:
            data.decode(enc)
            return enc
        except (UnicodeDecodeError, ValueError):
            continue
    return None


def is_binary(data: bytes) -> bool:
    return b"\x00" in data[:512]


def get_git_head_content(rel_path: str, cwd: str) -> bytes | None:
    """Get file content from git HEAD."""
    try:
        result = subprocess.run(
            ["git", "show", f"HEAD:{rel_path}"],
            capture_output=True,
            cwd=cwd,
        )
        if result.returncode == 0:
            return result.stdout
    except Exception:
        pass
    return None


def get_repo_root(cwd: str) -> str | None:
    try:
        result = subprocess.run(
            ["git", "rev-parse", "--show-toplevel"],
            capture_output=True,
            text=True,
            cwd=cwd,
        )
        if result.returncode == 0:
            return result.stdout.strip()
    except Exception:
        pass
    return None


def main() -> int:
    input_data = json.load(sys.stdin)
    tool_input = input_data.get("tool_input", {})
    file_path = tool_input.get("file_path", "")
    cwd = input_data.get("cwd", "")

    if not file_path or not os.path.isfile(file_path):
        return 0

    # Only check source files
    ext = os.path.splitext(file_path)[1].lower()
    if ext not in SOURCE_EXTS:
        return 0

    # Read current file
    try:
        with open(file_path, "rb") as f:
            current_data = f.read()
    except OSError:
        return 0

    if not current_data or is_binary(current_data):
        return 0

    # Get repo root and relative path
    repo_root = get_repo_root(cwd)
    if not repo_root:
        return 0

    # Normalize to forward slashes for git
    abs_path = os.path.abspath(file_path)
    rel_path = os.path.relpath(abs_path, repo_root).replace("\\", "/")

    # Get original from HEAD
    original_data = get_git_head_content(rel_path, repo_root)
    if original_data is None:
        return 0  # New file, not in git yet

    orig_enc = detect_encoding(original_data)
    curr_enc = detect_encoding(current_data)

    if orig_enc and curr_enc and orig_enc != curr_enc:
        print(
            f"WARNING: ENCODING CHANGED: {file_path}\n"
            f"  Original(HEAD): {orig_enc} -> Current: {curr_enc}\n"
            f"  文字コードが変更されています。元のエンコーディング({orig_enc})に戻してください。\n"
            f"  このファイルを{orig_enc}で保存し直す必要があります。"
        )

    return 0


if __name__ == "__main__":
    sys.exit(main())

"""pre-commit hook: scan all tracked files against denylist patterns."""

import os
import re
import subprocess
import sys


def load_denylist(path: str) -> list[tuple[str, re.Pattern]]:
    """Load patterns from the denylist file.

    Returns:
        [(raw_pattern, compiled_regex), ...]
    """
    if not os.path.isfile(path):
        raise RuntimeError(f"denylist file not found: {path}")

    patterns = []
    with open(path, "r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if not line or line.startswith("#"):
                continue
            patterns.append((line, re.compile(line)))
    return patterns


def tracked_files() -> list[str]:
    """Return all tracked files via git ls-files."""
    result = subprocess.run(
        ["git", "ls-files", "-z", "--", "src/"],
        capture_output=True,
    )
    if result.returncode != 0:
        raise RuntimeError(f"git ls-files failed: {result.stderr.decode()}")
    raw = result.stdout
    if not raw:
        return []
    return [p for p in raw.decode("utf-8").split("\0") if p]


def is_binary(data: bytes) -> bool:
    """True if null byte found in the first 512 bytes."""
    return b"\x00" in data[:512]


def scan_file(
    filepath: str,
    combined: re.Pattern,
    patterns: list[tuple[str, re.Pattern]],
) -> list[tuple[int, str, str]]:
    """Scan a file and return violations.

    Returns:
        [(line_number, line_content, pattern_str), ...]
    """
    try:
        data = open(filepath, "rb").read()
    except OSError:
        return []

    if not data or is_binary(data):
        return []

    # Decode: cp932 -> utf-8 -> latin-1 fallback
    text = None
    for enc in ("cp932", "utf-8"):
        try:
            text = data.decode(enc)
            break
        except (UnicodeDecodeError, ValueError):
            continue
    if text is None:
        text = data.decode("latin-1")

    violations = []
    for lineno, line in enumerate(text.splitlines(), start=1):
        if not combined.search(line):
            continue
        for raw, pat in patterns:
            if pat.search(line):
                violations.append((lineno, line.rstrip(), raw))

    return violations


def main() -> int:
    hooks_dir = os.path.dirname(os.path.abspath(__file__))
    denylist_path = os.path.join(hooks_dir, ".denylist")

    patterns = load_denylist(denylist_path)
    if not patterns:
        print("  denylist is empty, skipping.")
        return 0

    # Combined pattern for fast pre-screening
    combined_raw = "|".join(f"(?:{raw})" for raw, _ in patterns)
    combined = re.compile(combined_raw)

    files = tracked_files()
    if not files:
        print("  no tracked files.")
        return 0

    # Collect violations per file
    all_violations: dict[str, list[tuple[int, str, str]]] = {}
    for f in files:
        if not os.path.isfile(f):
            continue
        hits = scan_file(f, combined, patterns)
        if hits:
            all_violations[f] = hits

    if not all_violations:
        print("  no denylist violations found.")
        return 0

    # Report
    total = sum(len(v) for v in all_violations.values())
    print(f"\nDENYLIST: {total} violation(s) in {len(all_violations)} file(s):\n")
    for filepath, hits in sorted(all_violations.items()):
        print(f"  {filepath}:")
        for lineno, line, pat in hits:
            # Truncate long lines
            display = line if len(line) <= 120 else line[:117] + "..."
            print(f"    L{lineno}: [{pat}] {display}")
        print()

    return 1


if __name__ == "__main__":
    sys.exit(main())

